#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

class TrieNode {
public:
	TrieNode*
children[26];
	bool
isEndOfWord;
};

class Trie {
public:
	TrieNode*
root;
	void
insert(string word, TrieNode* root) {
		TrieNode*
newRoot = new TrieNode();
		for (int i=0;i<word.length();i++)
		{
			int charCode = word[i] - 'a';
			if (newRoot->children[charCode] == NULL) newRoot->children[charCode] = new TrieNode();
			newRoot = newRoot->children[charCode];
		}
		newRoot->isEndOfWord = true;
		root = newRoot;
	}
	void
remove(string word, TrieNode* root) {
		TrieNode*
newRoot = root;
		for (int i=0;i<word.length();i++)
		{
			int charCode = word[i] - 'a';
			if (newRoot->children[charCode] == NULL) return;
			newRoot = newRoot->children[charCode];
		}
		newRoot->isEndOfWord = false;
		if (newRoot->isEndOfWord == false) {
			for (int i=0;i<26;i++)
			{
				if (newRoot->children[i] != NULL) delete newRoot->children[i];
			}
			delete newRoot;
		} else {
			newRoot->isEndOfWord = false;
			newRoot->children = NULL;
		}
		root = newRoot;
	}
}

class Solution {
	public:
		void
autoCompletion(int n) {
		Trie trie;
		string word;
		for (int i=0;i<n;i++)
		{
			cin>>word;
			trie.insert(word, trie.root);
		}
	}
};

int
main() {
	Solution solution;
	int n;
	cin>>n;
	solution.autoCompletion(n);
	return 0;
}
